def _paint_block(grid, base_x, base_y, offset):
    """
    Paint a 5×5 block at (base_x, base_y - offset*5).

    * Top two rows → colour 0xc
    * Bottom three rows → colour 0x9
    Only paints over background colour 0x3.
    """
    y0 = base_y - offset * _BLOCK_H
    for dx in range(_BLOCK_W):
        x = base_x + dx
        if not (0 <= x < 64):
